async function main() {
  console.log('Updating', SKU_URLS.length, 'products with images...');
  let updated = 0, skipped = 0;
  for (const [sku, url] of SKU_URLS) {
    const p = await prisma.product.findFirst({ where: { sku }, select: { id: true, images: true } });
    if (!p) { skipped++; continue; }
    if (p.images && p.images.length > 0) { skipped++; continue; }
    await prisma.product.update({ where: { id: p.id }, data: { images: [url], thumbnail: url } });
    updated++;
    if (updated % 100 === 0) console.log(updated + ' updated...');
  }
  console.log('Done - Updated: ' + updated + ' | Skipped: ' + skipped);
  await prisma.$disconnect();
}
main().catch(async e => { console.error(e); await prisma.$disconnect(); process.exit(1); });